Consider the following C program:

#include<stdio.h>
int main() {
    int a;
    int arr[5] = {30, 50, 10};
    int *ptr;
    ptr = &arr[0] + 1;
    a = *ptr;
    (*ptr)++;
    ptr++;
    printf("%d", a + (*ptr) + arr[1]);
    return 0;
}

The output of the above program is ________. (Answer in integer)

The value of j at the end of the execution of the following C program:

int incr(int i) {
    static int count = 0;
    count = count + i;
    return (count);
}

main() {
    int i, j;
    for (i = 0; i <= 4; i++)
        j = incr(i);
}

is:

A. 10
B. 4
C. 6
D. 7
